+---
+import Layout from '../layouts/Layout.astro';
+
+const EXTERNAL_URL = 'https://clawclaw.jamieson9964.workers.dev/';
+
+function extractDivByClass(html: string, className: string) {
+  const startRe = new RegExp(
+    `<div\\b[^>]*class=["'][^"']*\\b${className}\\b[^"']*["'][^>]*>`,
+    'i'
+  );
+  const m = startRe.exec(html);
+  if (!m || m.index == null) return null;
+
+  const start = m.index;
+  const startTagEnd = start + m[0].length - 1;
+
+  // Minimal tag balancer: enough for this known, well-formed source.
+  const re = /<\/?div\b[^>]*>/gi;
+  re.lastIndex = startTagEnd + 1;
+
+  let depth = 1;
+  let match: RegExpExecArray | null;
+  while ((match = re.exec(html))) {
+    const tag = match[0];
+    if (tag.startsWith('</')) depth--;
+    else depth++;
+
+    if (depth === 0) {
+      const end = match.index;
+      return html.slice(startTagEnd + 1, end).trim();
+    }
+  }
+
+  return null;
+}
+
+let embeddedHtml: string | null = null;
+try {
+  const res = await fetch(EXTERNAL_URL);
+  if (!res.ok) throw new Error(`fetch failed: ${res.status}`);
+  const html = await res.text();
+  embeddedHtml = extractDivByClass(html, 'container');
+  // Remove the external page header (we render our own, blog-post style).
+  if (embeddedHtml) embeddedHtml = embeddedHtml.replace(/^\s*<header\b[\s\S]*?<\/header>\s*/i, '');
+} catch {
+  embeddedHtml = null;
+}
+---
+
+<Layout
+  title="Trust — OpenClaw"
+  description="OpenClaw Security Program — formal security initiative for AI agents that take real-world actions."
+>
+  <div class="stars"></div>
+  <div class="nebula"></div>
+
+  <main class="container">
+    <article class="article trust">
+      <header class="article-header">
+      <a href="/" class="back-link">← Back to home</a>
+        <h1 class="article-title">Trust</h1>
+      </header>
+
+      <div class="article-content">
+        <p>
+          Security posture, roadmap, and how we think about agents that can take real-world actions.
+        </p>
+
+        {embeddedHtml ? (
+          <section class="embedded" set:html={embeddedHtml} />
+        ) : (
+          <section class="embedded-fallback">
+            <p>
+              Could not load the security program right now.
+              <a href={EXTERNAL_URL} target="_blank" rel="noopener">Open it directly</a>.
+            </p>
+          </section>
+        )}
+      </div>
+    </article>
+  </main>
+</Layout>
+
+<style>
+  /* Starfield Background (keep consistent across pages) */
+  .stars {
+    position: fixed;
+    inset: 0;
+    background-image:
+      radial-gradient(2px 2px at 20px 30px, rgba(255,255,255,0.8), transparent),
+      radial-gradient(2px 2px at 40px 70px, rgba(255,255,255,0.5), transparent),
+      radial-gradient(1px 1px at 90px 40px, rgba(255,255,255,0.6), transparent),
+      radial-gradient(2px 2px at 130px 80px, rgba(255,255,255,0.4), transparent),
+      radial-gradient(1px 1px at 160px 120px, rgba(255,255,255,0.7), transparent),
+      radial-gradient(2px 2px at 200px 60px, rgba(0,229,204,0.6), transparent),
+      radial-gradient(1px 1px at 250px 150px, rgba(255,255,255,0.5), transparent),
+      radial-gradient(2px 2px at 300px 40px, rgba(255,77,77,0.4), transparent);
+    background-size: 350px 200px;
+    animation: twinkle 8s ease-in-out infinite alternate;
+    pointer-events: none;
+    z-index: 0;
+  }
+
+  @keyframes twinkle {
+    0% { opacity: 0.4; }
+    100% { opacity: 0.7; }
+  }
+
+  .nebula {
+    position: fixed;
+    inset: 0;
+    background:
+      radial-gradient(ellipse 80% 50% at 20% 20%, rgba(255, 77, 77, 0.12), transparent 50%),
+      radial-gradient(ellipse 60% 60% at 80% 30%, rgba(0, 229, 204, 0.08), transparent 50%),
+      radial-gradient(ellipse 90% 70% at 50% 90%, rgba(255, 77, 77, 0.06), transparent 50%);
+    pointer-events: none;
+    z-index: 0;
+  }
+
+  .container {
+    position: relative;
+    z-index: 1;
+    max-width: 720px;
+    margin: 0 auto;
+    padding: 40px 24px;
+    min-height: 100vh;
+    display: flex;
+    flex-direction: column;
+  }
+
+  .article {
+    animation: fadeInUp 0.6s ease-out;
+  }
+
+  @keyframes fadeInUp {
+    from { opacity: 0; transform: translateY(20px); }
+    to { opacity: 1; transform: translateY(0); }
+  }
+
+  .article-header {
+    margin-bottom: 48px;
+  }
+
+  .back-link {
+    display: inline-block;
+    margin-bottom: 32px;
+    color: var(--text-muted);
+    text-decoration: none;
+    font-size: 0.9rem;
+    transition: color 0.2s ease;
+  }
+
+  .back-link:hover { color: var(--coral-bright); }
+
+  .article-title {
+    font-family: var(--font-display);
+    font-size: clamp(2rem, 6vw, 3rem);
+    font-weight: 700;
+    line-height: 1.2;
+    margin-bottom: 0;
+    background: linear-gradient(135deg, var(--text-primary) 0%, var(--coral-bright) 100%);
+    -webkit-background-clip: text;
+    -webkit-text-fill-color: transparent;
+    background-clip: text;
+  }
+
+  .article-content {
+    line-height: 1.8;
+    color: var(--text-secondary);
+  }
+
+  .article-content :global(p:first-child) {
+    font-size: 1.25rem;
+    line-height: 1.7;
+    color: var(--text-primary);
+    margin-bottom: 16px;
+  }
+
+  .article-content :global(p) {
+    margin-bottom: 20px;
+  }
+
+  .embedded-fallback {
+    background: rgba(17, 24, 39, 0.55);
+    border: 1px solid var(--border-subtle);
+    border-radius: 16px;
+    padding: 18px;
+    color: var(--text-secondary);
+  }
+
+  .embedded-fallback a {
+    color: var(--coral-bright);
+    text-decoration: none;
+    text-decoration: underline;
+    text-underline-offset: 3px;
+  }
+
+  .embedded-fallback a:hover { color: var(--cyan-bright); }
+
+  /* External content: restyle to blog-post-like typography */
+  .article-content :global(.section) {
+    margin-top: 28px;
+  }
+
+  .article-content :global(h2) {
+    font-family: var(--font-display);
+    font-size: 1.5rem;
+    font-weight: 600;
+    color: var(--text-primary);
+    margin-top: 24px;
+    margin-bottom: 0;
+  }
+
+  .article-content :global(h3) {
+    margin-top: 20px;
+    margin-bottom: 0;
+    font-family: var(--font-display);
+    font-size: 1.25rem;
+    font-weight: 600;
+    color: var(--text-primary);
+  }
+
+  .article-content :global(h4) {
+    margin-top: 18px;
+    margin-bottom: 0;
+    font-family: var(--font-display);
+    font-size: 1.05rem;
+    font-weight: 600;
+    color: var(--text-primary);
+  }
+
+  .article-content :global(ul) {
+    margin-bottom: 12px;
+    padding-left: 24px;
+  }
+
+  .article-content :global(ol) {
+    margin-bottom: 12px;
+    padding-left: 24px;
+  }
+
+  .article-content :global(li) {
+    margin-bottom: 4px;
+    padding-left: 8px;
+  }
+
+  .article-content :global(li::marker) { color: var(--coral-bright); }
+
+  .article-content :global(strong) {
+    color: var(--text-primary);
+    font-weight: 600;
+  }
+
+  .article-content :global(a) {
+    color: var(--coral-bright);
+    text-decoration: underline;
+    text-underline-offset: 3px;
+  }
+
+  .article-content :global(a:hover) { color: var(--cyan-bright); }
+
+  .article-content :global(code) {
+    font-family: var(--font-mono);
+    font-size: 0.9em;
+    padding: 2px 6px;
+    border-radius: 4px;
+    background: var(--bg-elevated);
+    color: var(--cyan-bright);
+  }
+
+  .article-content :global(pre) {
+    padding: 20px;
+    border-radius: 12px;
+    background: var(--bg-elevated);
+    border: 1px solid var(--border-subtle);
+    overflow-x: auto;
+    margin-bottom: 24px;
+  }
+
+  .article-content :global(pre code) {
+    padding: 0;
+    background: transparent;
+    color: inherit;
+  }
+
+  /* Layout helpers from embedded content */
+  .article-content :global(.phases) {
+    display: grid;
+    grid-template-columns: repeat(2, minmax(0, 1fr));
+    gap: 14px;
+    margin-top: 14px;
+  }
+
+  @media (max-width: 820px) {
+    .article-content :global(.phases) { grid-template-columns: 1fr; }
+  }
+
+  .article-content :global(.phase) {
+    display: flex;
+    align-items: flex-start;
+    gap: 12px;
+    padding: 16px;
+    border-radius: 12px;
+    background: rgba(10, 15, 26, 0.7);
+    border: 1px solid var(--border-subtle);
+  }
+
+  .article-content :global(.phase-num) {
+    width: 38px;
+    height: 38px;
+    border-radius: 12px;
+    display: grid;
+    place-items: center;
+    font-weight: 900;
+    color: var(--bg-deep);
+    background: linear-gradient(135deg, var(--coral-bright) 0%, var(--cyan-bright) 100%);
+    flex: 0 0 auto;
+  }
+
+  .article-content :global(.table-wrap) {
+    overflow-x: auto;
+    -webkit-overflow-scrolling: touch;
+    margin-top: 12px;
+    margin-bottom: 20px;
+  }
+
+  .article-content :global(.table-wrap table) {
+    min-width: 640px;
+  }
+
+  .article-content :global(table) {
+    width: 100%;
+    border-collapse: collapse;
+    border-radius: 12px;
+    border: 1px solid var(--border-subtle);
+    background: rgba(10, 15, 26, 0.7);
+  }
+
+  .article-content :global(th),
+  .article-content :global(td) {
+    padding: 10px 12px;
+    border-bottom: 1px solid var(--border-subtle);
+    vertical-align: top;
+    color: var(--text-secondary);
+    font-size: 0.95rem;
+  }
+
+  .article-content :global(th) {
+    text-align: left;
+    color: var(--text-primary);
+    font-weight: 600;
+    background: rgba(17, 24, 39, 0.55);
+  }
+
+  .article-content :global(.report-box) {
+    margin-top: 12px;
+    padding: 18px;
+    border-radius: 12px;
+    border-left: 3px solid var(--coral-bright);
+    background: rgba(255, 77, 77, 0.05);
+  }
+
+  .article-content :global(.email-display) {
+    display: inline-block;
+    margin-top: 12px;
+    padding: 10px 12px;
+    border-radius: 8px;
+    background: var(--bg-elevated);
+    border: 1px solid var(--border-subtle);
+    font-family: var(--font-mono);
+    color: var(--cyan-bright);
+    font-weight: 600;
+  }
+
+  .article-content :global(.fields) {
+    display: flex;
+    flex-wrap: wrap;
+    gap: 8px;
+    margin-top: 12px;
+  }
+
+  .article-content :global(.field) {
+    padding: 6px 10px;
+    border-radius: 999px;
+    border: 1px solid var(--border-subtle);
+    background: rgba(17, 24, 39, 0.45);
+    color: var(--text-secondary);
+    font-size: 0.85rem;
+    white-space: nowrap;
+  }
+
+  .article-content :global(.checks) {
+    display: grid;
+    grid-template-columns: repeat(2, minmax(0, 1fr));
+    gap: 12px;
+    margin-top: 12px;
+    margin-bottom: 12px;
+  }
+
+  @media (max-width: 820px) {
+    .article-content :global(.checks) { grid-template-columns: 1fr; }
+  }
+
+  .article-content :global(.check) {
+    display: flex;
+    gap: 12px;
+    padding: 14px;
+    border-radius: 12px;
+    border: 1px solid var(--border-subtle);
+    background: rgba(10, 15, 26, 0.7);
+  }
+
+  .article-content :global(.check-icon) {
+    width: 32px;
+    height: 32px;
+    border-radius: 10px;
+    background: var(--cyan-bright);
+    display: grid;
+    place-items: center;
+    flex: 0 0 auto;
+  }
+
+  .article-content :global(.check-icon svg) {
+    width: 18px;
+    height: 18px;
+    stroke: var(--bg-deep) !important;
+  }
+
+  .article-content :global(.faq-item) {
+    padding: 14px;
+    border-radius: 12px;
+    border: 1px solid var(--border-subtle);
+    background: rgba(10, 15, 26, 0.7);
+    margin-top: 12px;
+  }
+
+  .article-content :global(.faq-q) {
+    color: var(--text-primary);
+    font-weight: 700;
+    letter-spacing: -0.01em;
+  }
+
+  .article-content :global(.faq-a) { margin-top: 8px; }
+
+  .article-content :global(.cta) {
+    display: flex;
+    gap: 12px;
+    flex-wrap: wrap;
+    margin-top: 18px;
+  }
+
+  .article-content :global(.btn) {
+    padding: 10px 16px;
+    border-radius: 10px;
+    font-size: 0.9rem;
+    font-weight: 600;
+    text-decoration: none;
+    transition: all 0.2s ease;
+    border: 1px solid var(--border-subtle);
+    background: rgba(17, 24, 39, 0.55);
+    color: var(--text-primary);
+    display: inline-flex;
+    align-items: center;
+    gap: 10px;
+  }
+
+  .article-content :global(.btn:hover) {
+    background: rgba(17, 24, 39, 0.75);
+    border-color: var(--text-secondary);
+    transform: translateY(-1px);
+  }
+
+  .article-content :global(.btn-primary) {
+    background: linear-gradient(135deg, rgba(255, 77, 77, 0.18) 0%, rgba(10, 15, 26, 0.8) 60%, rgba(0, 229, 204, 0.08) 100%);
+    border-color: rgba(255, 77, 77, 0.35);
+  }
+
+  .article-content :global(.btn-primary:hover) {
+    border-color: rgba(0, 229, 204, 0.35);
+  }
+
+  .article-content :global(footer) {
+    margin-top: 24px;
+    padding-top: 18px;
+    border-top: 1px solid var(--border-subtle);
+    text-align: center;
+    color: var(--text-muted);
+    font-size: 0.9rem;
+  }
+
+  @media (max-width: 480px) {
+    .container { padding: 24px 16px; }
+    .article-content :global(p:first-child) { font-size: 1.1rem; }
+  }
+</style>
